19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	const BLOCK_SIZE = 3;
22	const BLOCK_BASE_PREMIUM = 60;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	};
31	
32	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
33	
34	const isBlockOfAlike = (items: Item[]): boolean =>
35	  items.length === BLOCK_SIZE && items.every((i) => i.type === items[0].type);
36	
37	const itemsBasePremium = (items: Item[]): number => {
38	  if (isBlockOfAlike(items)) return BLOCK_BASE_PREMIUM;
39	  return items.reduce((sum, item) => sum + basePremiumOf(item), 0);
40	};
41	
42	const quoteStep = (step: QuoteStep): QuoteResult => {
43	  const itemsBase = itemsBasePremium(step.items);
44	  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
45	  return { premium: itemsBase + firstInsuranceSurcharge + PROCESSING_FEE };
46	};
47	
48	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
49	  const results = scenario.steps.map(quoteStep);
50	  return { results };
51	};
